# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import subprocess
import os
import tempfile
from google.cloud import storage


def image_converter(event, context):
    """Cloud Function triggered by Cloud Storage event to convert images using ImageMagick.
    
    Args:
        event (dict): The Cloud Storage event payload.
            - bucket: The bucket name.
            - name: The file name/path.
            - metadata: Custom metadata containing conversion options.
              - output_format: Target format (e.g., 'png', 'jpg', 'webp')
              - resize: Resize dimensions (e.g., '800x600')
              - quality: Output quality (e.g., '85')
              - rotate: Rotation degrees (e.g., '90')
              - grayscale: Whether to convert to grayscale ('true'/'false')
              - output_bucket: Destination bucket (optional, defaults to same bucket)
              - output_prefix: Output path prefix (optional, defaults to 'converted/')
        context: The event context (metadata about the event).
    """
    bucket_name = event['bucket']
    file_name = event['name']
    
    print(f"Processing file: {file_name} from bucket: {bucket_name}")
    print(f"Event ID: {context.event_id}, Event type: {context.event_type}")
    
    # Skip if the file is already in the converted directory to avoid infinite loops
    if file_name.startswith('converted/'):
        print(f"Skipping already converted file: {file_name}")
        return
    
    # Initialize Cloud Storage client
    storage_client = storage.Client()
    source_bucket = storage_client.bucket(bucket_name)
    source_blob = source_bucket.blob(file_name)
    
    # Reload blob to get metadata
    source_blob.reload()
    
    # Extract conversion options from metadata
    metadata = source_blob.metadata or {}
    
    output_format = metadata.get('output_format', 'png')
    resize = metadata.get('resize', None)
    quality = metadata.get('quality', None)
    rotate = metadata.get('rotate', None)
    grayscale = metadata.get('grayscale', 'false').lower() == 'true'
    output_bucket_name = metadata.get('output_bucket', bucket_name)
    output_prefix = metadata.get('output_prefix', 'converted/')
    
    # Validate output format
    allowed_formats = ['png', 'jpg', 'jpeg', 'webp', 'gif', 'bmp', 'tiff', 'pdf']
    if output_format.lower() not in allowed_formats:
        print(f"Unsupported output format: {output_format}. Allowed: {allowed_formats}")
        return
    
    # Validate file is an image
    supported_extensions = ('.png', '.jpg', '.jpeg', '.gif', '.bmp', '.tiff', '.tif', '.webp')
    if not file_name.lower().endswith(supported_extensions):
        print(f"Skipping non-image file: {file_name}")
        return
    
    # Create temporary directory for processing
    with tempfile.TemporaryDirectory() as tmp_dir:
        # Download source file
        source_path = os.path.join(tmp_dir, os.path.basename(file_name))
        source_blob.download_to_filename(source_path)
        print(f"Downloaded {file_name} to {source_path}")
        
        # Build output filename
        base_name = os.path.splitext(os.path.basename(file_name))[0]
        output_filename = f"{base_name}.{output_format.lower()}"
        output_path = os.path.join(tmp_dir, output_filename)
        
        # Build ImageMagick convert command
        convert_cmd = ['convert', source_path]
        
        # Apply conversion options
        if resize:
            # Validate resize format (e.g., '800x600', '50%')
            convert_cmd.extend(['-resize', resize])
            print(f"Applying resize: {resize}")
        
        if quality:
            try:
                quality_val = int(quality)
                if 1 <= quality_val <= 100:
                    convert_cmd.extend(['-quality', str(quality_val)])
                    print(f"Applying quality: {quality_val}")
                else:
                    print(f"Invalid quality value: {quality}. Must be between 1 and 100.")
            except ValueError:
                print(f"Invalid quality value: {quality}. Must be an integer.")
        
        if rotate:
            try:
                rotate_val = float(rotate)
                convert_cmd.extend(['-rotate', str(rotate_val)])
                print(f"Applying rotation: {rotate_val} degrees")
            except ValueError:
                print(f"Invalid rotate value: {rotate}. Must be a number.")
        
        if grayscale:
            convert_cmd.extend(['-colorspace', 'Gray'])
            print("Applying grayscale conversion")
        
        # Strip metadata for smaller file size
        convert_cmd.append('-strip')
        
        # Add output path
        convert_cmd.append(output_path)
        
        print(f"Executing command: {' '.join(convert_cmd)}")
        
        # Execute ImageMagick convert command
        return_code = subprocess.call(convert_cmd)
        
        if return_code != 0:
            print(f"ImageMagick convert failed with return code: {return_code}")
            raise RuntimeError(f"ImageMagick convert failed with return code {return_code}")
        
        print(f"Conversion successful. Output file: {output_path}")
        
        # Verify output file exists
        if not os.path.exists(output_path):
            print("Output file was not created.")
            raise FileNotFoundError("ImageMagick did not produce an output file.")
        
        output_file_size = os.path.getsize(output_path)
        print(f"Output file size: {output_file_size} bytes")
        
        # Upload converted file to destination bucket
        dest_bucket = storage_client.bucket(output_bucket_name)
        
        # Construct output blob path
        # Preserve directory structure from source
        source_dir = os.path.dirname(file_name)
        if source_dir:
            output_blob_path = f"{output_prefix}{source_dir}/{output_filename}"
        else:
            output_blob_path = f"{output_prefix}{output_filename}"
        
        output_blob = dest_bucket.blob(output_blob_path)
        
        # Set content type based on output format
        content_type_map = {
            'png': 'image/png',
            'jpg': 'image/jpeg',
            'jpeg': 'image/jpeg',
            'webp': 'image/webp',
            'gif': 'image/gif',
            'bmp': 'image/bmp',
            'tiff': 'image/tiff',
            'pdf': 'application/pdf',
        }
        content_type = content_type_map.get(output_format.lower(), 'application/octet-stream')
        
        # Add metadata to output blob
        output_metadata = {
            'source_file': file_name,
            'source_bucket': bucket_name,
            'conversion_format': output_format,
            'converted_by': 'cloud-function-imagemagick',
        }
        if resize:
            output_metadata['resize'] = resize
        if quality:
            output_metadata['quality'] = quality
        if rotate:
            output_metadata['rotate'] = rotate
        if grayscale:
            output_metadata['grayscale'] = 'true'
        
        output_blob.metadata = output_metadata
        
        output_blob.upload_from_filename(output_path, content_type=content_type)
        
        print(f"Uploaded converted file to gs://{output_bucket_name}/{output_blob_path}")
        print(f"Content-Type: {content_type}")
        
        return {
            'status': 'success',
            'source': f"gs://{bucket_name}/{file_name}",
            'output': f"gs://{output_bucket_name}/{output_blob_path}",
            'format': output_format,
            'size_bytes': output_file_size,
        }